CREATE TABLE `emailVerificationCodes` (
	`id` int AUTO_INCREMENT NOT NULL,
	`userId` int NOT NULL,
	`code` varchar(255) NOT NULL,
	`expiresAt` timestamp NOT NULL,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `emailVerificationCodes_id` PRIMARY KEY(`id`),
	CONSTRAINT `emailVerificationCodes_code_unique` UNIQUE(`code`)
);
ALTER TABLE `users` MODIFY COLUMN `openId` varchar(64);
ALTER TABLE `users` ADD `passwordHash` text;
ALTER TABLE `users` ADD `emailVerified` boolean DEFAULT false NOT NULL;
ALTER TABLE `users` ADD `emailVerificationToken` varchar(255);
ALTER TABLE `users` ADD CONSTRAINT `users_email_unique` UNIQUE(`email`);

